```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // packet_id (plain uint32_t)
        stream & packet_id;

        // username with length prefix
        stream & hexi::prefixed(username);

        // scores: write count first, then the vector using operator<<
        uint32_t count = static_cast<uint32_t>(scores.size());
        stream & count;
        stream << scores; // internally uses write_container

        // metadata as null-terminated string
        stream & hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use the stream's serialise mechanism
    stream.serialise(packet);

    return buffer;
}
```

