```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>
#include <string_view>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Wrap the read-only span in a Hexi buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    NetworkPacket pkt{};

    // 1. Read the packet_id (plain 32-bit integer)
    stream >> pkt.packet_id;

    // 2. Read the username using a length prefix (zero-copy into string_view)
    //    Then copy into std::string stored in NetworkPacket.
    std::string_view username_view;
    stream >> hexi::prefixed(username_view);
    pkt.username.assign(username_view.begin(), username_view.end());

    // 3. Read the score count, then read the scores container
    uint32_t score_count = 0;
    stream >> score_count;

    pkt.scores.resize(score_count);
    // Use Hexi container deserialisation
    stream.read_container(pkt.scores, score_count);

    // 4. Read the metadata string as null-terminated (zero-copy),
    //    then copy into std::string.
    std::string_view metadata_view;
    stream >> hexi::null_terminated(metadata_view);
    pkt.metadata.assign(metadata_view.begin(), metadata_view.end());

    // 5. Skip any remaining padding bytes (if any)
    //
    // The adaptor is backed by the provided span, so its size()
    // reflects the total buffer size. We advance the read head
    // to the end if there is leftover data.
    auto remaining = adaptor.size() - adaptor.read_position();
    if (remaining > 0) {
        adaptor.advance_read(remaining);
    }

    return pkt;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    PacketInfo info{};

    // 1. Use span() to get a zero-copy view of the packet_id (first 4 bytes).
    //    We treat it as a span<uint32_t> of size 1 for convenience.
    std::span<const uint32_t> id_span;
    stream >> hexi::span(id_span, 1);
    info.packet_id = id_span[0];

    // 2. Read username using prefixed adaptor to get a std::string_view
    stream >> hexi::prefixed(info.username);

    // 3. Skip the scores vector without reading its elements:
    //    - Read the count (uint32_t)
    //    - Skip count * sizeof(uint32_t) bytes
    uint32_t score_count = 0;
    stream >> score_count;

    std::size_t bytes_to_skip = static_cast<std::size_t>(score_count) * sizeof(uint32_t);
    if (bytes_to_skip > 0) {
        stream.skip(bytes_to_skip);
    }

    // We intentionally do not read metadata here since PacketInfo only
    // needs packet_id and username.

    return info;
}
