#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>

struct PacketHeader {
    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    std::vector<uint8_t> temp_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(temp_buffer);
    hexi::binary_stream stream(adaptor);

    auto header_bytes = stream.span<uint8_t>(4);

    PacketHeader header;
    header.version = header_bytes[0];
    header.flags = header_bytes[1];
    header.packet_id = static_cast<uint16_t>(header_bytes[2]) | (static_cast<uint16_t>(header_bytes[3]) << 8);

    return header;
}

std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    std::vector<uint8_t> temp_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(temp_buffer);
    hexi::binary_stream stream(adaptor);

    return stream.view();
}

