PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Create a read-only buffer adaptor over the span
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Get a zero-copy span view of the header bytes.
    // The header layout is:
    // [0] version  (uint8_t)
    // [1] flags    (uint8_t)
    // [2-3] packet_id (uint16_t, assumed native endianness)
    auto header_span = stream.span<std::byte>(sizeof(PacketHeader));

    // Map the bytes into our PacketHeader POD without copying
    PacketHeader header{};
    const uint8_t* data = reinterpret_cast<const uint8_t*>(header_span.data());

    header.version   = data[0];
    header.flags     = data[1];
    // Interpret the next two bytes as uint16_t; assuming native endianness here.
    header.packet_id = static_cast<uint16_t>(
        static_cast<uint16_t>(data[2]) |
