    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read the item count
    std::uint32_t item_count = 0;
    stream >> item_count;

    // Prepare a vector to hold the items
    std::vector<std::uint32_t> items;
    items.resize(item_count);

