```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

std::vector<uint8_t> read_buffer_data(const std::vector<uint8_t>& source_buffer, size_t bytes_to_read) {
    // Wrap the source buffer in a read-only adaptor
    hexi::buffer_adaptor adaptor(source_buffer);
    hexi::binary_stream stream(adaptor);

    // Do not read past the end of the provided source buffer
    const std::size_t available = source_buffer.size();
    const std::size_t to_read = std::min<std::size_t>(bytes_to_read, available);

    std::vector<std::uint8_t> result(to_read);

    if (to_read > 0) {
        // Read raw bytes into the destination vector
        stream.read(result.data(), to_read);
    }

    return result;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
    // Ensure the destination has enough space; buffer_adaptor operates
    // over the existing storage, so we must resize first.
    const std::size_t old_size = dest_buffer.size();
    dest_buffer.resize(old_size + source_data.size());

    // Create an adaptor over the destination buffer
    hexi::buffer_adaptor adaptor(dest_buffer);
    hexi::binary_stream stream(adaptor);

    // Move the write position to the end of the previously written data
    adaptor.advance_write(old_size);

    // Write the new data
    if (!source_data.empty()) {
        stream.write(source_data.data(), source_data.size());
    }
}
