#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <algorithm>

std::vector<uint8_t> peek_buffer_data(const std::vector<uint8_t>& buffer, size_t bytes_to_peek) {
    // Create a read-only adaptor over the input buffer.
    // Using a const span ensures we don't modify the underlying data.
    std::span<const std::uint8_t> span(buffer.data(), buffer.size());
    hexi::buffer_adaptor adaptor(span);

    // Determine how many bytes we can safely peek
    const auto available = adaptor.size();
    const auto to_copy = std::min<std::size_t>(bytes_to_peek, available);

    std::vector<std::uint8_t> result(to_copy);

    // Use buffer_adaptor::copy() to read without advancing the read cursor.
    // copy() returns the number of bytes actually copied.
    const auto copied = adaptor.copy(result.data(), result.size());
    result.resize(copied);

    return result;
}
