const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    // Use a read-only buffer adaptor over the existing storage.
    hexi::buffer_adaptor adaptor(std::span<const std::uint8_t>(buffer.data(), buffer.size()));
    // The current read pointer is simply the beginning of the readable region.
    // For a fresh adaptor, this is just buffer.data().
    return adaptor.size() > 0 ? buffer.data() : nullptr;
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    // Use a mutable buffer adaptor which tracks write position.
    hexi::buffer_adaptor adaptor(std::span<std::uint8_t>(buffer.data(), buffer.size()));
    // For a freshly constructed adaptor, write position is at the beginning,
    // so the write pointer is buffer.data() + current size (which is 0).
    // If the buffer is empty, return nullptr to indicate no storage.
    return buffer.empty() ? nullptr : buffer.data() + adaptor.size();
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    // Construct a read-only adaptor to query readable size.
    hexi::buffer_adaptor adaptor(std::span<const std::uint8_t>(buffer.data(), buffer.size()));

    BufferInfo info{};
    info.readable_size = adaptor.size();

    // For a std::vector-backed buffer, total capacity is buffer.capacity().
    // Free space is capacity minus current logical size.
    if (buffer.capacity() >= buffer.size()) {
        info.free_space = buffer.capacity() - buffer.size();
    } else {
        info.free_space = 0;
    }

    return info;
}
