#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <span>

struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result{};
    result.data_type = 0;

    if (buffer.empty()) {
        return result; // no data
    }

    // Create a buffer adaptor and binary stream over the read-only span
    hexi::buffer_adaptor adaptor(
        std::span<const std::byte>(
            reinterpret_cast<const std::byte*>(buffer.data()),
            buffer.size()));
    hexi::binary_stream stream(adaptor);

    // Preview the first byte (data_type) without advancing the read pointer
    // We can use the underlying buffer interface as a read-only view
    const auto& buf_read = stream.buffer();
    if (buf_read.size() < sizeof(uint8_t)) {
        return result; // insufficient data
    }

    result.data_type = static_cast<uint8_t>(
        std::to_integer<unsigned char>(buf_read[0]));

    // Now actually read from the stream (this advances the read pointer)
    uint8_t data_type{};
    uint32_t item_count{};

    stream >> data_type >> item_count;

    // Check that we have enough data for all items based on type
    const std::size_t remaining_bytes = buf_read.size() - stream.read_offset();
    const std::size_t needed_bytes =
        static_cast<std::size_t>(item_count) *
        (data_type == 0 ? sizeof(uint32_t) : sizeof(float));

    if (remaining_bytes < needed_bytes) {
        // Not enough data; return what we know (data_type from preview)
        return result;
    }

    if (data_type == 0) {
        // Integers
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            uint32_t value{};
            stream >> value;
            result.int_items[i] = value;
        }
    } else {
        // Floats
        result.float_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            float value{};
            stream >> value;
            result.float_items[i] = value;
        }
    }

    return result;
}
