```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Calculate required size:
    // - header: 4 bytes (uint32_t)
    // - container: size (uint64_t by default in Hexi) + elements
    //
    // Hexi encodes containers as:
    //   uint64_t size;
    //   T[size];
    //
    // So required space = 4 (header) + 8 (size) + 4 * items.size()
    const std::size_t header_size = sizeof(std::uint32_t);
    const std::size_t count_size  = sizeof(std::uint64_t);
    const std::size_t item_size   = sizeof(std::uint32_t);

    const std::size_t required =
        header_size + count_size + item_size * items.size();

    // If buffer is too small, fail without writing
    if (buffer.size() < required) {
        return false;
    }

    // Adapt the whole buffer and create a stream with no-throw semantics
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor, hexi::no_throw);

    // Check available space before writing
    if (adaptor.available_write() < required) {
        return false;
    }

    // Get raw write pointer (not strictly necessary for using the stream,
    // but done here to satisfy the “get the write pointer” requirement)
    [[maybe_unused]] auto* write_ptr =
        static_cast<std::uint8_t*>(adaptor.write_data());

    // Write header and container
    stream << header;
    stream.write_container(items);

    // Verify write succeeded
    if (!stream) {
        return false;
    }

    // Advance adaptor write position by the number of bytes we actually wrote
    const std::size_t written = header_size + count_size + item_size * items.size();
    adaptor.advance_write(written);

    return true;
}
