```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Adapt the read-only span into a Hexi buffer
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary_stream on top of the adaptor
    hexi::binary_stream stream(adaptor);

    // Use buffer_adaptor's pointer / size-style operations
    // (names are inferred from Hexi's design; adjust if your actual
    // buffer_adaptor API uses slightly different identifiers)
    auto const* read_ptr   = adaptor.read_data();   // current read pointer
    auto const  read_size  = adaptor.read_size();   // bytes available to read

    constexpr std::size_t header_size =
        sizeof(std::uint32_t) + sizeof(std::uint16_t) + sizeof(std::uint16_t);

    // Check that enough data is available for the header
    if (read_size < header_size) {
        // In a real application you might throw, return an error code,
        // or set a stream error. Here we return a zero-initialised header.
        return PacketHeader{};
    }

    // Use binary_stream's zero-copy operation to obtain a span
    // over the header bytes without copying them.
    std::span<const std::byte> header_view;
    stream.peek(header_view, header_size); // zero-copy view of next header_size bytes

    // Interpret the span as raw bytes and construct the header.
    // This assumes the buffer is laid out as:
    // [ magic (4 bytes) | version (2 bytes) | flags (2 bytes) ]
    const std::byte* ptr = header_view.data();

    PacketHeader header{};
    std::memcpy(&header.magic,   ptr,                         sizeof(header.magic));
    std::memcpy(&header.version, ptr + sizeof(header.magic),  sizeof(header.version));
    std::memcpy(&header.flags,   ptr + sizeof(header.magic) +
                                         sizeof(header.version), sizeof(header.flags));

    // Advance the stream past the header now that we've consumed it
    stream.skip(header_size);

    return header;
}
