#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>

struct MessagePacket {
    uint32_t header;
    std::string_view message;
};

MessagePacket read_header_and_message(const std::span<const uint8_t> buffer) {
    // Wrap the input span in a Hexi buffer_adaptor and binary_stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read the header
    uint32_t header{};
    stream >> header;

    // Get a view over the remaining bytes
    auto remaining = stream.view<std::span<const uint8_t>>();

    // Find the null terminator
    const uint8_t* begin = remaining.data();
    const uint8_t* end   = remaining.data() + remaining.size();
    const uint8_t* nul   = begin;

    for (; nul != end; ++nul) {
        if (*nul == 0) {
            break;
        }
    }

    // Construct string_view over the message bytes (up to but not including the null)
    std::string_view message{
        reinterpret_cast<const char*>(begin),
        static_cast<std::size_t>(nul - begin)
    };

    return MessagePacket{ header, message };
}
