#include <hexi/dynamic_buffer.h>
#include <vector>
#include <cstdint>
#include <cstring>

template<std::size_t block_size = 1024>
void write_to_dynamic_buffer(hexi::dynamic_buffer<block_size>& buffer,
                             std::uint32_t header,
                             const std::vector<std::uint8_t>& data) {
    // Write the 4‑byte header in native endianness
    buffer.write(&header, sizeof(header));

    // Write the raw payload bytes (if any)
    if (!data.empty()) {
        buffer.write(data.data(), data.size());
    }
}

template<std::size_t block_size = 1024>
struct BufferData {
    std::uint32_t header;
    std::vector<std::uint8_t> data;
};

inline BufferData<> read_from_dynamic_buffer(hexi::dynamic_buffer<1024>& buffer,
                                             std::size_t data_length) {
    BufferData<> result{};

    // Read the 4‑byte header
    buffer.read(&result.header, sizeof(result.header));

    // Read the payload
    result.data.resize(data_length);
    if (data_length > 0) {
        buffer.read(result.data.data(), data_length);
    }

    return result;
}
