```cpp
#include <hexi/dynamic_buffer.h>
#include <vector>
#include <cstdint>
#include <cstddef>

template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer,
                                           size_t bytes_to_peek) {
    // Limit peek size to the number of bytes currently readable
    const std::size_t available = buffer.read_available();
    const std::size_t to_copy   = (bytes_to_peek < available) ? bytes_to_peek : available;

    std::vector<uint8_t> out(to_copy);

    // dynamic_buffer is contiguous (Hexi uses contiguous buffers for stream IO),
    // and exposes indexed access without advancing the read cursor.
    for (std::size_t i = 0; i < to_copy; ++i) {
        out[i] = static_cast<uint8_t>(
            std::to_integer<unsigned char>(buffer[i])
        );
    }

    return out;
}
```

