    std::cout << "  a = " << static_cast<const void*>(a) << " value = " << std::hex << *a << '\n';
    std::cout << "  b = " << static_cast<const void*>(b) << " value = " << std::hex << *b << '\n';
    std::cout << "  c = " << static_cast<const void*>(c) << " value = " << std::hex << *c << '\n';

    // Deallocate in the order: B, then C.
    // Internally, deallocate() will "push" these blocks onto the freelist.
    alloc.deallocate(b);
    alloc.deallocate(c);

    std::cout << "\nAfter deallocating b then c (pushed onto freelist):\n";
    std::cout << "  deallocated b = " << static_cast<const void*>(b) << '\n';
    std::cout << "  deallocated c = " << static_cast<const void*>(c) << '\n';

    // Now allocate two more blocks. Because the freelist behaves like a
    // stack (LIFO), the allocator should "pop" C first, then B.
    value_type* d = alloc.allocate();
    value_type* e = alloc.allocate();

    std::cout << "\nNew allocations after freeing b and c (popped from freelist):\n";
    std::cout << "  d = " << static_cast<const void*>(d) << " value = " << std::hex << *d << '\n';
    std::cout << "  e = " << static_cast<const void*>(e) << " value = " << std::hex << *e << '\n';

    // Observations:
    //  - If the freelist is LIFO, `d` should be the same address as `c`,
    //    and `e` should be the same address as `b`.
    //  - The printed addresses and stored values allow us to confirm this
    //    behavior without accessing the private push()/pop() methods.
    std::cout << "\nObserved freelist behavior (expected LIFO):\n";
    std::cout << "  d == c ? " << (d == c ? "yes" : "no") << '\n';
    std::cout << "  e == b ? " << (e == b ? "yes" : "no") << '\n';

    // Clean up: deallocate all outstanding blocks.
    alloc.deallocate(a);
    alloc.deallocate(d);
    alloc.deallocate(e);

    std::cout << "\nAll blocks deallocated; freelist has been repopulated internally.\n";
}

