```cpp
#include <hexi/endian.h>
#include <cstdint>
#include <bit>

template<std::endian from, std::endian to, typename T>
T convert_endianness(T value) {
    // Use Hexi's conditional_reverse to perform endianness conversion
    return hexi::conditional_reverse<from, to>(value);
}

template<typename T>
T convert_endianness_runtime(T value, std::endian from, std::endian to) {
    // Dispatch to the compile-time version based on the runtime parameters
    if (from == std::endian::little && to == std::endian::big) {
        return convert_endianness<std::endian::little, std::endian::big>(value);
    } else if (from == std::endian::big && to == std::endian::little) {
        return convert_endianness<std::endian::big, std::endian::little>(value);
    } else if (from == std::endian::native && to == std::endian::little) {
        return convert_endianness<std::endian::native, std::endian::little>(value);
    } else if (from == std::endian::native && to == std::endian::big) {
        return convert_endianness<std::endian::native, std::endian::big>(value);
    } else if (from == std::endian::little && to == std::endian::native) {
        return convert_endianness<std::endian::little, std::endian::native>(value);
    } else if (from == std::endian::big && to == std::endian::native) {
        return convert_endianness<std::endian::big, std::endian::native>(value);
    }

    // Same endianness – no conversion needed
    return value;
}
