```cpp
#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min
#include <cstddef>   // for std::byte

template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(
    const hexi::detail::intrusive_storage<block_size>& storage,
    size_t bytes_to_preview
) {
    // Compute how many bytes are actually readable
    const auto readable =
        (storage.write_offset >= storage.read_offset)
            ? static_cast<size_t>(storage.write_offset - storage.read_offset)
            : static_cast<size_t>(0); // intrusive_storage is not circular

    const size_t to_copy = std::min(readable, bytes_to_preview);
    std::vector<uint8_t> out;
    out.reserve(to_copy);

    // storage_type may not be uint8_t, so copy byte-wise
    for (size_t i = 0; i < to_copy; ++i) {
        const auto& v = storage.storage[storage.read_offset + i];
        // reinterpret each element as a sequence of bytes
        const auto* p = reinterpret_cast<const std::byte*>(&v);
        for (size_t b = 0; b < sizeof(v) && out.size() < to_copy; ++b) {
            out.push_back(static_cast<uint8_t>(p[b]));
        }
    }

    return out;
}

template<size_t block_size = 1024>
struct BufferStatus {
    size_t readable_size;
    size_t free_space;
};

inline BufferStatus<> check_buffer_status(
    const hexi::detail::intrusive_storage<1024>& storage
) {
    BufferStatus<> status{};

    // Amount of readable data is write_offset - read_offset
    status.readable_size =
        (storage.write_offset >= storage.read_offset)
            ? static_cast<size_t>(storage.write_offset - storage.read_offset)
            : static_cast<size_t>(0);

    // Free space is capacity minus current write_offset
    status.free_space =
        (storage.write_offset <= 1024)
            ? static_cast<size_t>(1024 - storage.write_offset)
            : static_cast<size_t>(0);

    return status;
}

template<size_t block_size = 1024>
void reset_buffer(hexi::detail::intrusive_storage<block_size>& storage) {
    // Use the provided clear() to reset offsets
    storage.clear();
}
