#include <gtest/gtest.h>
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>
#include <fstream>

// Include the implementation
#include "implementation.hpp"

// Helper function to create a test file
void create_test_file(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    std::ofstream file(file_path, std::ios::binary);
    file.write(reinterpret_cast<const char*>(data.data()), data.size());
    file.close();
}

TEST(FileBuffer, ReadFileData) {
    std::filesystem::path test_file = "test_read.bin";
    std::vector<uint8_t> test_data = {1, 2, 3, 4, 5, 6, 7, 8};
    create_test_file(test_file, test_data);

    auto result = read_file_data(test_file, 4);

    EXPECT_EQ(4, result.size());
    EXPECT_EQ(1, result[0]);
    EXPECT_EQ(2, result[1]);
    EXPECT_EQ(3, result[2]);
    EXPECT_EQ(4, result[3]);

    std::filesystem::remove(test_file);
}

TEST(FileBuffer, PreviewFileData) {
    std::filesystem::path test_file = "test_preview.bin";
    std::vector<uint8_t> test_data = {10, 20, 30, 40, 50};
    create_test_file(test_file, test_data);

    // Preview should not advance read pointer
    auto preview1 = preview_file_data(test_file, 3);
    auto preview2 = preview_file_data(test_file, 3);

    EXPECT_EQ(3, preview1.size());
    EXPECT_EQ(10, preview1[0]);
    EXPECT_EQ(20, preview1[1]);
    EXPECT_EQ(30, preview1[2]);

    // Both previews should be the same
    EXPECT_EQ(preview1, preview2);

    std::filesystem::remove(test_file);
}

TEST(FileBuffer, WriteFileData) {
    std::filesystem::path test_file = "test_write.bin";
    std::vector<uint8_t> test_data = {100, 200, 150, 250};

    write_file_data(test_file, test_data);

    // Verify by reading back
    auto read_back = read_file_data(test_file, test_data.size());
    EXPECT_EQ(test_data, read_back);

    std::filesystem::remove(test_file);
}

TEST(FileBuffer, GetFileSize) {
    std::filesystem::path test_file = "test_size.bin";
    std::vector<uint8_t> test_data = {1, 2, 3, 4, 5, 6};
    create_test_file(test_file, test_data);

    size_t file_size = get_file_size(test_file);

    EXPECT_EQ(test_data.size(), file_size);

    std::filesystem::remove(test_file);
}

TEST(FileBuffer, ReadWriteRoundTrip) {
    std::filesystem::path test_file = "test_roundtrip.bin";
    std::vector<uint8_t> original = {42, 84, 126, 168};

    write_file_data(test_file, original);
    auto read_back = read_file_data(test_file, original.size());

    EXPECT_EQ(original, read_back);

    std::filesystem::remove(test_file);
}

