#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    hexi::file_buffer buffer(file_path); // open for reading by default

    // Limit the read size to what is actually available
    const auto available = buffer.size();
    const auto to_read   = static_cast<size_t>(std::min<std::uintmax_t>(
        static_cast<std::uintmax_t>(bytes_to_read),
        available
    ));

    std::vector<std::uint8_t> out(to_read);
    if (to_read > 0) {
        buffer.read(out.data(), to_read);
    }
    return out;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    hexi::file_buffer buffer(file_path); // open for reading

    const auto available = buffer.size();
    const auto to_preview = static_cast<size_t>(std::min<std::uintmax_t>(
        static_cast<std::uintmax_t>(bytes_to_preview),
        available
    ));

    std::vector<std::uint8_t> out(to_preview);
    if (to_preview > 0) {
        // Use copy to read without advancing the read pointer
        buffer.copy(out.data(), to_preview);
    }
    return out;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    // Open in write mode (truncate/overwrite, depending on Hexi's file_buffer ctor/options)
    hexi::file_buffer buffer(file_path, hexi::file_mode::write);

    if (!data.empty()) {
        buffer.write(data.data(), data.size());
    }
}

size_t get_file_size(const std::filesystem::path& file_path) {
    hexi::file_buffer buffer(file_path); // open for reading
    return static_cast<size_t>(buffer.size());
}
