```cpp
#include <hexi/file_buffer.h>
#include <filesystem>

size_t get_file_readable_size(const std::filesystem::path& file_path) {
    // Open the file in binary read mode using Hexi's file_buffer
    hexi::file_buffer fb(file_path.string().c_str(), "rb");
    if (!fb) {
        // If the buffer is invalid (e.g., file can't be opened), return 0
        return 0;
    }

    // Hexi's file_buffer exposes size() as the total readable size
    return fb.size();
}

bool is_file_buffer_valid(const std::filesystem::path& file_path) {
    // Attempt to construct a file_buffer; it will track its own error state
    hexi::file_buffer fb(file_path.string().c_str(), "rb");

    // file_buffer has an operator bool() that returns true if it's in a good state
    return static_cast<bool>(fb);
}
