int32_t read_int32_from_file(const std::filesystem::path& file_path) {
    // Open file in binary read mode using Hexi's file_buffer
    hexi::file_buffer buffer(file_path.string().c_str(), "rb");
    hexi::binary_stream stream(buffer);  // throwing stream by default

    int32_t value{};
    stream >> value;

    if (!stream) {
