```cpp
#include <hexi/static_buffer.h>

template<size_t buffer_size = 1024>
struct BufferInfo {
    size_t capacity;
    size_t current_size;
    size_t free_space;
};

BufferInfo<> get_buffer_info(const hexi::static_buffer<std::byte, 1024>& buffer) {
    BufferInfo<> info{};

    // Total capacity is the template parameter of static_buffer
    info.capacity = 1024;

    // static_buffer is a contiguous range; size() gives the amount of readable data.
    // This assumes static_buffer follows the common container interface.
    const auto current_size = buffer.size();
    info.current_size = current_size;

    // Free space is capacity minus currently stored readable bytes.
    info.free_space = info.capacity - info.current_size;

    return info;
}
```

