```cpp
#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(
    const hexi::static_buffer<std::byte, buffer_size>& buffer,
    size_t bytes_to_preview
) {
    // We assume Hexi's static_buffer exposes the readable size via size()
    // and provides indexed access that does *not* advance the read pointer.
    const std::size_t available = buffer.size();
    const std::size_t to_copy   = std::min<std::size_t>(available, bytes_to_preview);

    std::vector<std::uint8_t> result;
    result.reserve(to_copy);

    for (std::size_t i = 0; i < to_copy; ++i) {
        // Accessing by index must not change the buffer's read position.
        const std::byte b = buffer[i];
        result.push_back(static_cast<std::uint8_t>(b));
    }

    return result;
}
```

