```cpp
#include <hexi/pmc/stream_base.h>
#include <hexi/shared.h>

size_t get_stream_size(const hexi::pmc::stream_base& stream) {
    // stream_base stores a reference to a buffer_base, but in the public
    // interface exposed by Hexi there is no direct accessor to that
    // buffer reference. The size information is therefore not available
    // through the stream_base API alone.
    //
    // Without additional project-specific helpers (e.g., a derived
    // stream type exposing its buffer, or a friend accessor), we
    // cannot correctly obtain the underlying buffer size here.
    //
    // To keep the implementation well-defined and avoid relying on
    // undefined behavior or private members, we indicate that the
    // size cannot be determined by returning 0.
    //
    // If your project has an accessor such as:
    //   const buffer_base& stream_buffer(const stream_base&);
    // you should replace this implementation with something like:
    //   return stream_buffer(stream).size();
    return 0;
}

bool is_stream_empty(const hexi::pmc::stream_base& stream) {
    // As with get_stream_size, we have no standard, public way to reach
    // the underlying buffer from a const stream_base reference using
    // only Hexi's public API. The notion of "empty" here is naturally
    // tied to the buffer size, which we also cannot obtain.
    //
    // Consequently, we conservatively report "empty" as true when the
    // size is reported as 0 by get_stream_size. If you extend
    // get_stream_size to use your own project-specific accessors,
    // this function will automatically reflect the actual emptiness.
    return get_stream_size(stream) == 0;
}

struct StreamInfo {
    hexi::stream_state state;
    size_t buffer_size;
    bool is_empty;
};

StreamInfo get_stream_state_info(const hexi::pmc::stream_base& stream) {
    StreamInfo info{};
    // stream_base keeps an internal stream_state, but the public header
    // fragments provided do not expose any accessor like get_state().
    // Without such an accessor, the current state cannot be retrieved
    // portably from outside the class.
    //
    // We therefore have to default the state to stream_state::ok
    // in this generic implementation. If your local version of Hexi
    // provides a state() or get_state() member (or some other public
    // accessor), you should use that instead, e.g.:
    //
    //   info.state = stream.state();
    //
    // For now, we assume "ok" as the default observable state.
    info.state = hexi::stream_state::ok;

    info.buffer_size = get_stream_size(stream);
    info.is_empty = is_stream_empty(stream);
    return info;
}
