#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <string>

void write_string_to_stream(hexi::pmc::binary_stream_writer& writer, const std::string& str) {
    // Prefixed format: first write the length, then the raw bytes
    std::uint32_t size = static_cast<std::uint32_t>(str.size());
    writer.write(size);                             // write length prefix
    writer.write(str.data(), str.size());           // write string bytes
}

std::string read_string_from_stream(hexi::pmc::binary_stream_reader& reader) {
    // Read length prefix, then read that many bytes into a std::string
    std::uint32_t size = 0;
    reader.read(size);                              // read length prefix

    std::string result;
    result.resize(size);
    if (size > 0) {
        reader.read(result.data(), size);           // read string bytes
    }

    return result;
}
