#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring>

void write_data_to_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                          uint32_t value,
                          const void* data,
                          std::size_t length) {
    // Write the 32-bit integer value in binary form
    buffer.write(&value, sizeof(value));

    // Write the raw byte array
    if (length > 0 && data != nullptr) {
        buffer.write(data, length);
    }
