```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring> // for std::memcpy
#include <stdexcept>

void skip_bytes_in_buffer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                          std::size_t bytes) {
    // Advance the read position by `bytes` without copying data out.
    //
    // The Hexi buffer_read interface (base of buffer_adaptor) exposes
    // `advance_read(std::size_t)` to move the read pointer forward.
    //
    // Using it directly avoids any unnecessary allocations or copies.
    buffer.advance_read(bytes);
}

struct MessageHeader {
    uint16_t message_type;
    uint32_t body_length;
};

MessageHeader read_header_and_skip_body(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    MessageHeader header{};

    // The buffer_adaptor ultimately derives from pmc::buffer_read, which
    // exposes:
    //   - std::size_t size() const;
    //   - std::byte& operator[](std::size_t);
    //   - void advance_read(std::size_t);
    //
    // We can read the header fields directly from the underlying buffer via
    // operator[] and then move the read pointer past them.

    constexpr std::size_t header_size =
        sizeof(header.message_type) + sizeof(header.body_length);

    // Ensure there are enough bytes for the header itself.
    // (If the project normally uses Hexi's error-handling / state,
    //  this could be converted to that instead of throwing.)
    if (buffer.size() < header_size) {
        throw std::runtime_error("Not enough data to read MessageHeader");
    }

    // Read message_type (2 bytes)
    {
        std::byte raw[sizeof(header.message_type)];
        for (std::size_t i = 0; i < sizeof(header.message_type); ++i) {
            raw[i] = buffer[i];
        }
        std::memcpy(&header.message_type, raw, sizeof(header.message_type));
    }

    // Read body_length (4 bytes) – immediately after message_type
    {
        const std::size_t offset = sizeof(header.message_type);
        std::byte raw[sizeof(header.body_length)];
        for (std::size_t i = 0; i < sizeof(header.body_length); ++i) {
            raw[i] = buffer[offset + i];
        }
        std::memcpy(&header.body_length, raw, sizeof(header.body_length));
    }

    // Move read pointer past the header we just consumed.
    buffer.advance_read(header_size);

    // Now skip the body based on body_length.
    if (buffer.size() < header.body_length) {
        throw std::runtime_error("Not enough data to skip message body");
    }
    buffer.advance_read(header.body_length);

    return header;
}
