```cpp
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

const void* get_read_pointer(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    // For a contiguous range like std::vector<std::byte>, the underlying data
    // pointer is the base address. The current read position is represented
    // by buffer.read(), which returns the current read index.
    //
    // So the current read pointer is:
    //   data() + read_index
    if (buffer.size() == 0) {
        // If the buffer is empty, there is no valid read pointer.
        // Return nullptr to indicate this.
        return nullptr;
    }

    auto& underlying = buffer.get_buffer();
    return static_cast<const void*>(underlying.data() + buffer.read());
}

struct BufferState {
    std::size_t size;
    const void* read_ptr;
    bool is_empty;
};

BufferState get_buffer_state(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    BufferState state{};
    state.size = buffer.size();
    state.is_empty = buffer.empty();
    state.read_ptr = get_read_pointer(buffer);
    return state;
}
