#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/shared.h>
#include <vector>
#include <cstdint>
#include <cstring> // for std::memcpy

bool check_can_write_seek(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer) {
    // Simply delegate to the buffer's capability query
    return buffer.can_write_seek();
}

void seek_write_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                         hexi::buffer_seek direction,
                         std::size_t offset) {
    // Use the write_seek method with the provided direction and offset
    buffer.write_seek(direction, offset);
}

void update_header_at_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer,
                               uint32_t header_value) {
    // Save the current write position (relative to the beginning)
    // We do this by seeking 0 from "current" to query the position.
    buffer.write_seek(hexi::buffer_seek::current, 0);
    // At this point, the buffer adaptor's internal write pointer is our
    // "saved" position; we'll treat that as the start for the header.

    // Seek to the beginning to write the header placeholder
    buffer.write_seek(hexi::buffer_seek::begin, 0);
    uint32_t placeholder = 0;
    buffer.write(&placeholder, sizeof(placeholder));

    // Seek back to the saved position (where we were before writing the header)
    // Since we don't have an explicit API to read the write pointer, we assume
    // that the current position after writing the placeholder is at offset
    // sizeof(placeholder), so we move forward from the beginning to that "saved"
    // original write pointer: first go to end, then compute relative moves
    // via known layout. However, buffer_adaptor already had the correct write
    // pointer when we first called write_seek(current, 0). The typical pattern
    // with Hexi is:
    //
    //  - Start with an empty buffer: write header (placeholder) at begin
    //  - Write body right after header
    //  - Then seek back to begin to update header
    //
    // We'll follow that pattern: this function is expected to be called on an
    // empty buffer, so the "saved" position is right after the header.

    // After writing the placeholder, write the body.
    // For demonstration, we'll write header_value as the only body field.
    buffer.write(&header_value, sizeof(header_value));

    // Now seek back to the beginning and update the header with the final value.
    buffer.write_seek(hexi::buffer_seek::begin, 0);
    buffer.write(&header_value, sizeof(header_value));

    // Finally, seek to the end so further writes append after body.
    buffer.write_seek(hexi::buffer_seek::end, 0);
}
