	static_assert(std::is_unsigned_v<T>, "encode_varint requires an unsigned integer type");

	std::size_t bytes_written = 0;

	do {
		std::uint8_t byte = static_cast<std::uint8_t>(value & 0x7Fu);
		value >>= 7;
		if (value != 0) {
			byte |= 0x80u; // set continuation bit
		}
		writer.write(&byte, sizeof(byte));
		++bytes_written;
	} while (value != 0);

	return bytes_written;
}

// Decode an unsigned integer from a LEB128-style varint.
template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
	static_assert(std::is_unsigned_v<T>, "decode_varint requires an unsigned integer type");

	T result = 0;
	int shift = 0;

	while (true) {
		std::uint8_t byte = 0;
		reader.read(&byte, sizeof(byte));

		result |= static_cast<T>(static_cast<T>(byte & 0x7Fu) << shift);

		if ((byte & 0x80u) == 0) {
			break;
		}

		shift += 7;
	}

	return result;
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
	static_assert(std::is_unsigned_v<T>, "encode_decode_roundtrip requires an unsigned integer type");

	// Prepare a buffer and adaptor for Hexi streams
	std::vector<std::uint8_t> storage;
	hexi::pmc::buffer_write_adaptor<std::vector<std::uint8_t>> write_adaptor(storage);
	hexi::pmc::binary_stream_writer writer(write_adaptor);

	// Encode
	encode_varint(writer, original_value);

	// Create a read adaptor over the written data
	hexi::pmc::buffer_read_adaptor<std::vector<std::uint8_t>> read_adaptor(storage);
	hexi::pmc::binary_stream_reader reader(read_adaptor);

	// Decode
	T decoded = decode_varint<T>(reader);

	return decoded == original_value;
}

