```cpp
#include <hexi/shared.h>
#include <cstring>
#include <cstddef>

using namespace hexi::detail;

// Check if two memory regions [src, src + src_len) and [dst, dst + dst_len)
// overlap in address space.
bool check_regions_overlap(const void* src, std::size_t src_len,
                           const void* dst, std::size_t dst_len) {
    // Zero-length regions never overlap
    if (src_len == 0 || dst_len == 0) {
        return false;
    }

    auto src_begin = static_cast<const std::byte*>(src);
    auto dst_begin = static_cast<const std::byte*>(dst);
    auto src_end   = src_begin + src_len; // one past the last byte
    auto dst_end   = dst_begin + dst_len; // one past the last byte

    // Two half-open intervals [a, a+n) and [b, b+m) overlap iff:
    // a < b+m && b < a+n
    return (src_begin < dst_end) && (dst_begin < src_end);
}

// Copy memory safely from source to destination.
// Returns false if regions overlap (copy not performed), true otherwise.
bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
    if (length == 0) {
        return true; // nothing to do, trivially safe
    }

    if (check_regions_overlap(source, length, destination, length)) {
        // Overlapping regions: do not perform the copy
        return false;
    }

    std::memcpy(destination, source, length);
    return true;
}
