#include <hexi/shared.h>
#include <array>
#include <cstdint>

using namespace hexi::detail;

template<std::size_t Size>
constexpr auto create_filled_array(std::uint8_t value) {
    // Use Hexi's byte_type (likely std::byte) and construct from uint8_t
    using storage_type = std::byte;
    std::array<storage_type, Size> result{};

    for (std::size_t i = 0; i < Size; ++i) {
        result[i] = static_cast<storage_type>(value);
    }

    return result;
}

bool verify_filled_array(const auto& arr, std::uint8_t expected_value) {
    using storage_type = typename std::remove_cvref_t<decltype(arr)>::value_type;
    const auto expected = static_cast<storage_type>(expected_value);

    for (const auto& elem : arr) {
        if (elem != expected) {
            return false;
        }
    }
    return true;
}
