    std::vector<std::byte> dest2(10);
    auto info2 = safe_read_with_limit_check(stream, dest2.data(), dest2.size());

    EXPECT_TRUE(info2.occurred);
    EXPECT_EQ(5, info2.read_limit);
    EXPECT_GT(info2.total_read, 0);
}

