```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct CompactPacket {
    uint32_t packet_id;
    std::vector<std::string> tags;
    std::string data;
};

std::vector<uint8_t> serialize_compact_packet(const CompactPacket& packet) {
    // Underlying buffer to hold the serialized data
    std::vector<uint8_t> buffer;

    // Create a Hexi buffer adaptor over the vector
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary stream for writing
    hexi::binary_stream stream(adaptor);

    // Write the packet_id as a regular 32-bit integer
    stream << packet.packet_id;

    // Wrap the stream with the prefixed_varint adaptor.
    // This makes containers / strings written through it use
    // a varint-encoded size prefix.
    auto compact_stream = hexi::prefixed_varint(stream);

    // Serialize tags and data with compact (varint-prefixed) encoding
    compact_stream << packet.tags;
    compact_stream << packet.data;

    return buffer;
}

CompactPacket deserialize_compact_packet(const std::span<const uint8_t> buffer) {
    CompactPacket packet{};

    // Create a read-only buffer adaptor over the span
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary stream for reading
    hexi::binary_stream stream(adaptor);

    // Read the packet_id
    stream >> packet.packet_id;

    // Wrap the stream with the prefixed_varint adaptor for compact decoding
    auto compact_stream = hexi::prefixed_varint(stream);

    // Deserialize tags and data using varint-prefixed sizes
    compact_stream >> packet.tags;
    compact_stream >> packet.data;

    return packet;
}
