struct PaddedData {
    uint16_t header;
    std::string data;
    uint32_t footer;
};

std::vector<uint8_t> serialize_with_padding(const PaddedData& packet) {
    // Use a std::vector<uint8_t> as the underlying buffer
    std::vector<uint8_t> buffer;

    // Create a Hexi buffer adaptor and binary stream for writing
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Write header (uint16_t)
    stream << packet.header;

    // Write data with a length prefix.
    // Hexi's binary_stream supports std::string and will typically
    // encode it with a length prefix followed by the bytes.
    stream << packet.data;

    // Write exactly 16 bytes of 0x00 padding using the fill helper
    stream.fill<16>(0x00);

    // Write footer (uint32_t)
    stream << packet.footer;

    // The adaptor has written directly into 'buffer', so just return it
    return buffer;
}
