```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm> // for std::min

std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Backing buffer that the adaptors will operate on
    std::vector<std::uint8_t> backing_buffer;

    // Reserve at least the size of input_data so we have enough space
    backing_buffer.resize(input_data.size());

    // Create a write adaptor over the backing buffer
    hexi::pmc::buffer_write_adaptor write_adaptor(backing_buffer);

    // Ensure there is enough free space before writing
    std::size_t to_write = std::min<std::size_t>(input_data.size(), write_adaptor.free());
    if (to_write > 0) {
        write_adaptor.write(input_data.data(), to_write);
    }

    // Now create a read adaptor over the same backing buffer
    hexi::pmc::buffer_read_adaptor read_adaptor(backing_buffer);

    // Prepare output buffer of readable size
    std::size_t readable = read_adaptor.size();
    std::vector<std::uint8_t> output(readable);

    if (readable > 0) {
        read_adaptor.read(output.data(), readable);
    }

    return output;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // Create a read adaptor over the provided data
    hexi::pmc::buffer_read_adaptor read_adaptor(const_cast<std::vector<std::uint8_t>&>(buffer_data));

    // Limit peek_size to what is actually available
    std::size_t available = read_adaptor.size();
    std::size_t actual_peek = std::min<std::size_t>(peek_size, available);

    std::vector<std::uint8_t> peeked(actual_peek);

    if (actual_peek == 0) {
        return peeked;
    }

    // Use read_ptr() to get the current read position (non-advancing)
    const std::uint8_t* current_read_ptr =
        static_cast<const std::uint8_t*>(read_adaptor.read_ptr());

    // Use copy() (non-advancing) to peek at the data
    read_adaptor.copy(peeked.data(), actual_peek);

    // At this point, the adaptor's read pointer has not advanced.
    // Verify that read_ptr() still points at the same location, then consume using read().
    (void)current_read_ptr; // suppress unused variable warning if not otherwise used

    // Now actually consume the data using read()
    std::vector<std::uint8_t> consumed(actual_peek);
    read_adaptor.read(consumed.data(), actual_peek);

    // Return what we peeked (same bytes as consumed)
    return peeked;
}
