```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <algorithm>

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create an adaptor over an initially empty std::vector<uint8_t> that will
    // grow as we write to it.
    std::vector<std::uint8_t> buffer;
    hexi::pmc::buffer_write_adaptor adaptor(buffer);

    for (const auto& chunk : chunks) {
        const std::uint8_t* data = chunk.data();
        std::size_t remaining = chunk.size();

        // Write this chunk in several calls to write(), respecting free()
        while (remaining > 0) {
            std::size_t avail = adaptor.free();

            // If there is no free space reported, break to avoid a tight loop.
            if (avail == 0) {
                break;
            }

            std::size_t to_write = std::min(avail, remaining);
            adaptor.write(data, to_write);

            data      += to_write;
            remaining -= to_write;
        }
    }

    // Return the final size of the buffer as tracked by the adaptor
    return adaptor.size();
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create a read adaptor over the input buffer
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    std::vector<std::uint8_t> result;
    result.reserve(buffer.size());

    while (adaptor.size() > 0) {
        // Only read a portion of the available data
        std::size_t to_read = std::min(chunk_size, adaptor.size());
        std::vector<std::uint8_t> temp(to_read);

        adaptor.read(temp.data(), to_read);

        // adaptor.size() now reflects remaining data after this read
        result.insert(result.end(), temp.begin(), temp.end());
    }

    // Read until buffer is empty; return all collected bytes
    return result;
}
