#include <hexi/pmc/buffer_read_adaptor.h>
#include <vector>
#include <cstdint>
#include <cstring>

struct Header {
    uint32_t magic;
    uint16_t version;
};

Header peek_header_without_reading(const std::vector<uint8_t>& buffer) {
    // Create a read adaptor over the const buffer. This does NOT own or modify
    // the underlying storage; it just tracks a read cursor.
    hexi::pmc::buffer_read_adaptor adaptor(buffer);

    Header header{};

    // Peek at the header bytes without consuming them.
    // copy() copies from the current read position but does not advance it.
    adaptor.copy(reinterpret_cast<std::byte*>(&header), sizeof(Header));

    // Use read_ptr() to obtain a pointer to the current read position.
    // Since we only used copy(), the read cursor should still be at the start
    // of the buffer, pointing to the first byte.
    const std::byte* ptr = adaptor.read_ptr();

    // Optionally verify that read_ptr() indeed points to the start of the
    // supplied buffer. This is a sanity check; it doesn't affect the result.
    if (!buffer.empty()) {
        const auto* buf_ptr =
            reinterpret_cast<const std::byte*>(buffer.data());
        // If the library's semantics are as expected, ptr should equal buf_ptr.
        // We do not enforce this with an assertion here, but the call to
        // read_ptr() demonstrates how to access the current position.
        (void)buf_ptr;
    }

    // Return the header that was peeked without advancing the read cursor.
    return header;
}

