    std::vector<uint16_t> data_values;
    uint32_t checksum;
};

std::vector<uint8_t> serialize_protocol_packet(const ProtocolPacket& packet) {
    // Backing buffer for serialization
    std::vector<uint8_t> buffer;

    // Adapt the buffer for Hexi
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    using hexi::endian::native_to_big;

    // Convert and write message_id
    uint32_t be_message_id = native_to_big(packet.message_id);
    stream.write(&be_message_id, sizeof(be_message_id));

    // First write the number of data_values as uint32_t, big-endian
    uint32_t count = static_cast<uint32_t>(packet.data_values.size());
    uint32_t be_count = native_to_big(count);
    stream.write(&be_count, sizeof(be_count));

    // Prepare a temporary vector with big-endian converted uint16_t values
    std::vector<uint16_t> be_data_values;
    be_data_values.reserve(packet.data_values.size());
    for (uint16_t v : packet.data_values) {
        be_data_values.push_back(native_to_big(v));
    }

    // Write the container of big-endian values
    stream.write_container(be_data_values);

    // Convert and write checksum
    uint32_t be_checksum = native_to_big(packet.checksum);
    stream.write(&be_checksum, sizeof(be_checksum));

    return buffer;
}

ProtocolPacket deserialize_protocol_packet(const std::span<const uint8_t> buffer) {
    ProtocolPacket packet{};

    // Adapt the input span for Hexi
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    using hexi::endian::big_to_native;

    // Read and convert message_id
    uint32_t be_message_id = 0;
    stream.read(&be_message_id, sizeof(be_message_id));
    packet.message_id = big_to_native(be_message_id);

    // Read and convert count of data_values
    uint32_t be_count = 0;
    stream.read(&be_count, sizeof(be_count));
    uint32_t count = big_to_native(be_count);

    // Read container of uint16_t values in big-endian representation
    std::vector<uint16_t> be_data_values;
    be_data_values.resize(count);
    stream.read_container(be_data_values);

    // Convert each value from big-endian to native
    packet.data_values.reserve(count);
    for (uint16_t be_v : be_data_values) {
        packet.data_values.push_back(big_to_native(be_v));
    }

    // Read and convert checksum
    uint32_t be_checksum = 0;
    stream.read(&be_checksum, sizeof(be_checksum));
    packet.checksum = big_to_native(be_checksum);

    return packet;
}

struct ProtocolHeader {
    uint32_t message_id;
};

ProtocolHeader extract_protocol_header(const std::span<const uint8_t> buffer) {
    ProtocolHeader header{};

    // Adapt the span to a binary_stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    using hexi::endian::big_to_native;

    // Get a zero-copy span over the first 4 bytes (message_id)
    auto id_span = stream.span<std::uint8_t>(sizeof(uint32_t));

    // Interpret span as big-endian uint32_t and convert to native
    uint32_t be_message_id = 0;
    std::memcpy(&be_message_id, id_span.data(), sizeof(be_message_id));
    header.message_id = big_to_native(be_message_id);

    // Advance past the header (4 bytes)
    stream.skip(sizeof(uint32_t));

    return header;
}
