#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>
#include <span>
#include <string_view>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    // Serialization (const) – write to stream
    void serialise(auto& adaptor) const {
        using hexi::endian::conditional_reverse;

        // 1. Write sensor_id directly (assume uint32_t is handled as-is by stream)
        adaptor.write(sensor_id);

        // 2. Write temperature count, then each temperature as little-endian
        uint32_t count = static_cast<uint32_t>(temperatures.size());
        adaptor.write(count);

        for (float temp : temperatures) {
            float le_temp = conditional_reverse(
                temp,
                std::endian::native,
                std::endian::little
            );
            adaptor.write(le_temp);
        }

        // 3. Write pressure as little-endian
        double le_pressure = conditional_reverse(
            pressure,
            std::endian::native,
            std::endian::little
        );
        adaptor.write(le_pressure);
    }

    // Deserialization (non-const) – read from stream
    void serialise(auto& adaptor) {
        using hexi::endian::little_to_native_inplace;

        // 1. Read sensor_id directly
        adaptor.read(sensor_id);

        // 2. Read count, then that many temperatures in little-endian
        uint32_t count = 0;
        adaptor.read(count);
        temperatures.resize(count);

        for (uint32_t i = 0; i < count; ++i) {
            adaptor.read(temperatures[i]);
            little_to_native_inplace(temperatures[i]);
        }

        // 3. Read pressure in little-endian
        adaptor.read(pressure);
        little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<std::uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use the stream's serialise method to serialize the entire structure
    stream.serialise(data);

    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    MeasurementData result;

    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use the stream's deserialise method to deserialize the entire structure
    stream.deserialise(result);

    return result;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    SensorInfo info{};

    // 1. Use view to extract a null-terminated sensor name string (if present)
    //    Assume the binary format is: [null-terminated char[]][sensor_id][...]
    //
    //    view returns a std::string_view into the buffer without copying.
    info.sensor_name = stream.view<char>();

    // 2. Use enforce_read_bounds to check if there's enough data before reading sensor_id
    stream.enforce_read_bounds(sizeof(uint32_t));

    // 3. Read the sensor_id (uint32_t) directly
    stream.read(info.sensor_id);

    // 4. Skip the remaining data using skip
    //    Skip whatever remains in the buffer after sensor_id.
    auto remaining = adaptor.size() - adaptor.read_pos();
    if (remaining > 0) {
        stream.skip(remaining);
    }

    return info;
}
